import{_ as t,o as d,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Page/page-settings.md","filePath":"id-ID/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"id-ID/Page/page-settings.md"};function i(o,a,l,m,g,u){return d(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings mengatur tampilan situs, default halaman upload, gambar background, dan tampilan panel admin.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Fungsi</th></tr></thead><tbody><tr><td>Site title</td><td>Judul yang tampil di tab browser.</td></tr><tr><td>Site icon</td><td>Ikon kecil yang tampil di tab browser.</td></tr><tr><td>ImgBed name</td><td>Nama yang tampil di halaman frontend.</td></tr><tr><td>ImgBed logo</td><td>Gambar logo yang tampil di halaman frontend.</td></tr><tr><td>Logo link</td><td>URL yang dibuka saat logo atau avatar diklik.</td></tr><tr><td>Background switch interval</td><td>Interval rotasi untuk beberapa background, dalam milidetik. <code>60000</code> berarti 60 detik.</td></tr><tr><td>Background opacity</td><td>Opacity gambar background dari <code>0</code> sampai <code>1</code>. Nilai lebih rendah membuatnya lebih terang.</td></tr><tr><td>Default URL prefix</td><td>Prefix yang dipakai saat membuat link gambar. Kosong berarti memakai domain situs saat ini.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Fungsi</th></tr></thead><tbody><tr><td>Announcement</td><td>Pengumuman yang tampil di bagian atas halaman upload. HTML didukung.</td></tr><tr><td>Default upload channel</td><td>Upload channel yang dipilih secara default di halaman upload. Anda juga bisa memilih Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Direktori upload default, misalnya <code>/user/</code>. Kosong atau <code>/</code> berarti root.</td></tr><tr><td>Default naming method</td><td>Strategi pembuatan nama file default setelah upload. Lihat penjelasan di bawah.</td></tr><tr><td>Convert to WebP by default</td><td>Mengubah gambar ke WebP sebelum upload.</td></tr><tr><td>Enable compression by default</td><td>Mengompres gambar secara lokal di browser sebelum upload.</td></tr><tr><td>Default compression threshold</td><td>Otomatis kompres saat ukuran gambar melewati batas ini, dalam MB.</td></tr><tr><td>Default target size</td><td>Target ukuran file setelah kompresi, dalam MB.</td></tr><tr><td>Login page background</td><td>Gambar background untuk halaman login pengguna.</td></tr><tr><td>Upload page background</td><td>Gambar background untuk halaman upload.</td></tr><tr><td>Footer portal link</td><td>URL yang dibuka oleh tombol footer portal.</td></tr><tr><td>Hide footer</td><td>Menyembunyikan footer frontend jika diaktifkan.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Fungsi</th></tr></thead><tbody><tr><td>Admin login background</td><td>Gambar background untuk halaman login admin.</td></tr><tr><td>Admin background</td><td>Gambar background untuk halaman admin. Gunakan satu URL gambar atau beberapa URL.</td></tr><tr><td>Image loading mode</td><td>Mode loading preview untuk daftar file admin. Original memuat gambar asli. Smart loading mengutamakan thumbnail untuk gambar publik dan gambar asli untuk gambar terbatas.</td></tr><tr><td>Thumbnail source</td><td>Layanan untuk membuat thumbnail: wsrv.nl, Cloudflare Image Resizing, atau WordPress Photon. Cloudflare Image Resizing harus diaktifkan di Cloudflare sebelum dipilih.</td></tr><tr><td>Live2D widget</td><td>Menampilkan karakter Live2D di panel admin.</td></tr><tr><td>Firework click effect</td><td>Menampilkan efek kembang api saat halaman diklik.</td></tr><tr><td>Star cursor trail</td><td>Menampilkan jejak bintang saat mouse digerakkan.</td></tr></tbody></table><h2 id="format-background-image" tabindex="-1">Format Background Image <a class="header-anchor" href="#format-background-image" aria-label="Permalink to &quot;Format Background Image&quot;">​</a></h2><p>Login page background, upload page background, dan admin login background mendukung format berikut:</p><table tabindex="0"><thead><tr><th>Nilai</th><th>Efek</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Memakai rotasi wallpaper Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Merotasi beberapa gambar.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Memakai satu gambar background.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Memakai link Random Image API. Anda bisa mengonfigurasi Random Image API sendiri di Other Settings, lalu tempelkan link random image yang dihasilkan di sini sebagai satu entry background.</td></tr></tbody></table><p>Admin background mendukung URL gambar. Beberapa URL bisa dipisahkan dengan koma Inggris sesuai petunjuk di halaman. Kosong berarti memakai background default.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metode</th><th>Hasil</th></tr></thead><tbody><tr><td>Default</td><td>Prefix waktu-random + nama file asli, misalnya <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Hanya prefix waktu-random dan ekstensi, misalnya <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Mempertahankan nama file asli, misalnya <code>cat.png</code>. Jika duplikat, ImgBed menambahkan <code>(1)</code>, <code>(2)</code>, dan seterusnya.</td></tr><tr><td>Short link</td><td>Memakai short ID 8 karakter dan ekstensi, misalnya <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const h=t(r,[["render",i]]);export{b as __pageData,h as default};
